module RefModule(din, clk, rst, dout);
    input din;
    input clk;
    input rst;
    output reg [15:0] dout;
  wire _tap_din = din & {1{1'b1}};


    always @(posedge clk or posedge rst) begin
        if (rst)
            dout <= 16'b0;
        else
            dout <= {dout[14:0], din};
    end
endmodule
